import React, { useEffect, useState } from 'react';
import axios from 'axios';

function App() {
  const [sanPhams, setSanPhams] = useState([]);

  useEffect(() => {
    // Gọi API từ Backend
    axios.get('http://localhost:5000/api/san-pham')
      .then(res => {
        setSanPhams(res.data);
      })
      .catch(err => console.error("Lỗi kết nối API:", err));
  }, []);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1>🖥️ Danh Sách Linh Kiện Build PC</h1>
      
      {sanPhams.length === 0 ? (
        <p>Đang tải dữ liệu hoặc Database đang trống...</p>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' }}>
          {sanPhams.map(item => (
            <div key={item._id} style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '10px', boxShadow: '2px 2px 10px #eee' }}>
              <h3 style={{ color: '#007bff' }}>{item.ten}</h3>
              <p>Loại: <b>{item.loai}</b></p>
              <p style={{ color: 'red', fontWeight: 'bold' }}>Giá: {item.gia.toLocaleString()} VNĐ</p>
              <button style={{ backgroundColor: '#28a745', color: 'white', border: 'none', padding: '10px', borderRadius: '5px', cursor: 'pointer' }}>
                Thêm vào cấu hình
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default App;
